Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <algorithm>

// Function to count the occurrences of a word in a line
int countWordInLine(const std::string &line, const std::string &word) {
    std::string lineCopy = line;
    std::transform(lineCopy.begin(), lineCopy.end(), lineCopy.begin(), ::tolower);
    std::string wordCopy = word;
    std::transform(wordCopy.begin(), wordCopy.end(), wordCopy.begin(), ::tolower);

    size_t pos = 0;
    int count = 0;
    while ((pos = lineCopy.find(wordCopy, pos)) != std::string::npos) {
        ++count;
        pos += wordCopy.length();
    }
    return count;
}

int main() {
    std::string fileName;
    std::string word;

    std::cout << "Enter the file name: ";
    std::cin >> fileName;
    std::cout << "Enter the word to search for: ";
    std::cin >> word;

    std::ifstream file(fileName);
    if (!file.is_open()) {
        std::cerr << "Error opening file." << std::endl;
        return 1;
    }

    int totalCount = 0;
    std::string line;
    while (std::getline(file, line)) {
        totalCount += countWordInLine(line, word);
    }

    file.close();

    std::cout << "The word '" << word << "' occurred " << totalCount << " times in the file." << std::endl;

    return 0;
}
```

